// Expect: msg.topic in {t_isi,t_sniff, t_fms}, msg.payload boolean
const t = String(msg.topic || '');
let v = msg.payload;
if (typeof v === 'string') v = /^(true|on|1)$/i.test(v);

// Only store known keys
if (['t_isi', 't_sniff', 't_fms'].includes(t)) {
  flow.set(t, !!v);
  node.status({ fill: v ? 'green' : 'grey', shape: 'dot', text: `${t}=${!!v}` });
}
return null;    // store-only; no downstream output

const isi   = !!flow.get('t_isi');
const sniff = !!flow.get('t_sniff');
const fms   = !!flow.get('t_fms');

let parts = [];
if (isi)    parts.push('isi');
if (sniff)  parts.push('sniff');
if (fms)    parts.push('fms');

const roles = parts.join(' ');  // e.g "isi sniff", "sniff" "fms isi", ...
msg.payload = `ROLES="${roles}"\n`;
msg.filename = '/tmp/pi_roles.conf';
node.status({
    fill:'blue',
    shape:'dot',
    text: msg.payload.trim()
    });
return msg;

