// Prepare HTTP headers for ZIP download and hand filename to cleanup.
// Output 1: HTTP response
// Output 2: { payload: <full zip path> } for rm-zip exec

// 1) No filename -> 404
if (!msg.filename) {
    msg.statusCode = 404;
    msg.headers = {
        'Cache-Control': 'no-store',
        'Content-Type': 'text/plain; charset=utf-8'
    };
    msg.payload = 'No ZIP prepared yet.';
    return [msg, null];
}

// 2) ZIP read failed -> 500
if (!Buffer.isBuffer(msg.payload)) {
    msg.statusCode = 500;
    msg.headers = {
        'Cache-Control': 'no-store',
        'Content-Type': 'text/plain; charset=utf-8'
    };
    msg.payload = 'ZIP read failed (payload not Buffer).';
    return [msg, null];
}

// 3) Happy path: serve ZIP and schedule cleanup
var full = String(msg.filename || '');
var base = full.split(/[\\/]/).pop() || 'tracefiles.zip';

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/zip',
    'Content-Disposition': 'attachment; filename="' + base + '"',
    'Cache-Control': 'no-store'
};

// Second output: tell rm-zip which file to delete
var cleanupMsg = { payload: full };

return [msg, cleanupMsg];

// Build a static 2-bar dataset for ui_chart: Used vs Free (GB)

const s = msg.payload || {};

const usedPct = Number(s.disk_used_pct || 0);   // e.g. 8
const freeGb  = Number(s.disk_avail_gb || 0);   // free space in GB

let totalGb = 0;

if (usedPct >= 0 && usedPct < 100 && freeGb >= 0) {
    // total = free * 100 / (100 - used%)
    totalGb = freeGb * 100 / (100 - usedPct);
} else {
    totalGb = freeGb;
}

const usedGb = totalGb - freeGb;

function round1(n) {
    if (!isFinite(n)) return 0;
    return Math.round(n * 10) / 10;
}

const used = round1(usedGb);
const free = round1(freeGb);

// ui_chart "static dataset" format
msg.payload = [{
    series: ["Used", "Free"],
    data:   [[used], [free]],
    labels: ["Disk"]
}];

// optional: tell chart.js to start at 0 on Y axis
msg.ui_control = {
    options: {
        tooltips: {
            enabled: false
        },
        scales: {
            yAxes: [{ ticks: { beginAtZero: true } }]
        }
    }
};

return msg;

// Use the exact same id we armed with and provide the POST form
const id = flow.get('dl_cmd_id');
if (!id) return null;

msg.socketid = flow.get('last_socket'); // same tab
msg.action   = 'download_zip';
msg.method   = 'POST';
msg.url      = '/dlz2';

msg._id = id;            // <-- must match the armed id
msg.ts  = Date.now();    // <-- must satisfy fresh(msg.ts)
msg.form = { token: id };// <-- what your template puts into #dl_token

return msg;

// Save socket id when the dashboard connects OR switches tabs
if ((msg.payload === 'connected' || msg.payload === 'change') && msg.socketid) {
  flow.set('last_socket', msg.socketid);
  node.status({ fill: "green", shape: "dot", text: msg.socketid.slice(0,6) });
}
return null;

// Generate a one-time id and remember it for this tab
const id = Date.now().toString(36) + Math.random().toString(36).slice(2,6);
flow.set('dl_cmd_id', id);

return {
  socketid: flow.get('last_socket'), // optional: target this tab only
  arm: true,
  _id: id,              // <-- the id the widget will remember
  ts: Date.now()        // <-- passes your fresh() check
};

// TEMP: accept any token; just normalize for downstream
const body = (msg.req && msg.req.body) || {};
msg.form = { token: body.token || '' };
return msg;

const s = (msg.payload||'').toString().trim();
