function pad(n) { return (n < 10 ? '0' : '') + n; }

const d = new Date();

const ts =
  pad(d.getHours()) + ':' +
  pad(d.getMinutes()) + ':' +
  pad(d.getSeconds());

msg.payload = ts;
return msg;

// Convert uptime_s (seconds) into a friendly string, e.g. "1d 2h 03m"
const s = Number(msg.payload.uptime_s || 0);

if (!s) {
    msg.payload = "";
    return msg;
}

const days  = Math.floor(s / 86400);
const hours = Math.floor((s % 86400) / 3600);
const mins  = Math.floor((s % 3600) / 60);

let out = "";
if (days)  out += days + "d ";
if (hours || days) out += hours + "h ";
out += (mins < 10 && (hours || days) ? "0" : "") + mins + "m";

msg.payload = out;
return msg

const s = msg.payload || {};

const usedPct = Number(s.disk_used_pct || 0);   // percent used
const freeGb  = Number(s.disk_avail_gb || 0);   // free GB

let totalGb = 0;
if (usedPct >= 0 && usedPct < 100 && freeGb >= 0) {
    totalGb = freeGb * 100 / (100 - usedPct);
} else {
    totalGb = freeGb;
}
const usedGb = totalGb - freeGb;

function fmt(n) {
    if (!isFinite(n)) return "?";
    const v = Math.max(n, 0);
    const s = v.toFixed(1);
    return s.endsWith(".0") ? s.slice(0, -2) : s;
}

msg.payload = `${fmt(usedGb)} / ${fmt(totalGb)} GB  (${usedPct.toFixed(1)}%)`;
return msg;

msg.headers = {
  "Content-Type": "image/png"
};
return msg;

// msg.payload contains contents of /etc/pi_roles.conf
// e.g. ROLES="isi ethsniff"

const text = String(msg.payload || "");

// Capture everything inside the quotes (can be multiple words)
const m = text.match(/ROLES\s*=\s*\"?([^\"]*)\"?/);
const roleStr = m ? m[1] : "";

// Split on whitespace to get individual tokens
const tokens = roleStr.split(/\s+/).filter(Boolean);

const isi = tokens.includes("isi");
const sniff = tokens.includes("sniff");
const fms = tokens.includes("fms");

// Store in flow context so fnBuildRoles sees the same truth
flow.set("t_isi", isi);
flow.set("t_sniff", sniff);
flow.set("t_fms", fms);

// Drive the three switches
return [
    { topic: "t_isi", payload: isi },
    { topic: "t_sniff", payload: sniff },
    { topic: "t_fms", payload: fms }
];

const s = msg.payload || {};
// Use 1-minute load from pi-stats.sh
let v = Number(s.load1);

// Fallback to 0 if not a number
if (!isFinite(v)) v = 0;

msg.payload = v;
return msg;

// msg.payload: "ISI=1\nFMS=0\nWSBR0=1\n..."
const lines = (msg.payload || "").split(/\r?\n/);
const mods = {};

for (const line of lines) {
  const m = line.match(/^([A-Z0-9_]+)=(0|1)\s*$/);
  if (!m) continue;
  mods[m[1]] = (m[2] === "1");
}

// store globally if you ever want it elsewhere
global.set("initboxModules", mods);

msg.modules = mods;
return msg;

// When STOP ALL is pressed, turn all toggles off.
// Outputs:
//  1 -> ISI switch (swISI)
//  2 -> ETHsniffer switch (swWS)
//  3 -> FMS switch

const off = (topic) => ({ topic, payload: false });

return [
    off("t_isi"),   // ISI OFF
    off("t_sniff"), // ETHsniffer OFF
    off("t_fms")    // FMS OFF
];

